mapper.select:
select b.data_id as data_type, b.data_id as data_id, c.resource_id as dir_id, c.parent_resource_id as parent_dir_id, c.resource_name as name, c.resource_source_pk_id as dataset_id from byai_space_dir a join byai_space_dir_rel b on a.dir_id = b.dir_id join ss_resource c on b.data_id = c.resource_id
b.data_type in ('RESOURCE') and c.resource_status in (2)
and a.dir_type = #{dirType}
and a.session_id = #{sessionId}
